using Microsoft.ML;
using Microsoft.ML.Data;
using ChurnPredictor.Models;

var builder = WebApplication.CreateBuilder(args);

// Train the model and register pooled prediction engine
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
var data = mlContext.Data.LoadFromTextFile<CustomerInput>(dataPath, hasHeader: true, separatorChar: ',');

var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerInput.Region))
    .Append(mlContext.Transforms.Concatenate("Features", nameof(CustomerInput.Age), nameof(CustomerInput.Income), "RegionEncoded", nameof(CustomerInput.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.FastTree(labelColumnName: "Label"));

var model = pipeline.Fit(split.TrainSet);

// Evaluate and log metrics
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

// Save model and register pooled prediction engine
var modelPath = Path.Combine(AppContext.BaseDirectory, "churn_model.zip");
mlContext.Model.Save(model, data.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with customer data");

app.MapPost("/predict", (PredictionEnginePool<CustomerInput, ChurnPrediction> pool, CustomerRequest request) =>
{
    var input = new CustomerInput
    {
        Age = request.Age,
        Income = request.Income,
        Region = request.Region,
        PurchaseHistory = request.PurchaseHistory
    };

    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Probability = prediction.Probability
    });
});

app.Run();

